# ── Core Functions ───────────────────────────────────────────────────────

def initialize():
    """Load the bot on startup."""
    try:
        bot.load()
        return True
    except FileNotFoundError as e:
        print(f"Setup error: {e}")
        return False


def respond(message: str, chat_history: list):
    """Handle user message and return response with updated system info."""
    global query_count, total_response_time

    if not message.strip():
        return "", chat_history, get_system_info_html()

    if bot.llm is None:
        chat_history.append({"role": "user", "content": message})
        chat_history.append({"role": "assistant", "content": "The bot is not initialized. Please ensure the model and vector store are set up."})
        return "", chat_history, get_system_info_html()

    start = time.time()
    result = bot.ask(message)
    elapsed = time.time() - start

    query_count += 1
    total_response_time += elapsed

    answer = result["answer"]
    sources = result["sources"]

    response = answer
    if sources:
        source_list = ", ".join(s.replace('.txt', '').replace('_', ' ').title() for s in sources)
        response += f"\n\n---\n*Sources: {source_list} | Response time: {elapsed:.1f}s*"

    chat_history.append({"role": "user", "content": message})
    chat_history.append({"role": "assistant", "content": response})
    return "", chat_history, get_system_info_html()


def handle_example(example_text, chat_history):
    """Handle clicking an example question."""
    return respond(example_text, chat_history)


def refresh_system_info():
    """Refresh system info panel."""
    return get_system_info_html()


